class QuadTreeNode {
    int val;
    boolean isLeaf;
    QuadTreeNode[] children;

    public QuadTreeNode() {
        this.children = new QuadTreeNode[4];
        this.isLeaf = false;
    }

    public QuadTreeNode(int val) {
        this.val = val;
        this.isLeaf = true;
        this.children = null;
    }
}

public class QuadTreeCompression {

    public static QuadTreeNode buildQuadTree(int[][] matrix, int x, int y, int size) {
        if (size == 1) {
            return new QuadTreeNode(matrix[x][y]);
        }

        boolean allSame = true;
        int firstVal = matrix[x][y];
        for (int i = x; i < x + size; i++) {
            for (int j = y; j < y + size; j++) {
                if (matrix[i][j] != firstVal) {
                    allSame = false;
                    break;
                }
            }
            if (!allSame) break;
        }

        if (allSame) {
            return new QuadTreeNode(firstVal);
        } else {
            QuadTreeNode node = new QuadTreeNode();
            int newSize = size / 2;
            node.children[0] = buildQuadTree(matrix, x, y, newSize);
            node.children[1] = buildQuadTree(matrix, x, y + newSize, newSize);
            node.children[2] = buildQuadTree(matrix, x + newSize, y, newSize);
            node.children[3] = buildQuadTree(matrix, x + newSize, y + newSize, newSize);
            return node;
        }
    }

    public static void printQuadTree(QuadTreeNode root, String indent) {
        if (root == null) {
            return;
        }
        if (root.isLeaf) {
            System.out.println(indent + root.val);
        } else {
            System.out.println(indent + "|");
            printQuadTree(root.children[0], indent + "| ");
            printQuadTree(root.children[1], indent + "| ");
            printQuadTree(root.children[2], indent + "| ");
            printQuadTree(root.children[3], indent + "| ");
        }
    }

    public static void main(String[] args) {
        int[][] matrix = {
            {2, 2, 3, 3},
            {2, 2, 3, 3},
            {4, 2, 5, 5},
            {2, 3, 5, 5}
        };

        QuadTreeNode root = buildQuadTree(matrix, 0, 0, matrix.length);
        printQuadTree(root, "");
    }
}


